import{_ as t,o,c as s,ag as d}from"./chunks/framework.Bo7atV7P.js";const b=JSON.parse('{"title":"Responsive settings","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/responsive-settings.md","filePath":"concepts/responsive-settings.md","lastUpdated":1776245656000}'),a={name:"concepts/responsive-settings.md"};function n(i,e,r,c,l,h){return o(),s("div",null,[...e[0]||(e[0]=[d(`<h1 id="responsive-settings" tabindex="-1">Responsive settings <a class="header-anchor" href="#responsive-settings" aria-label="Permalink to &quot;Responsive settings&quot;">​</a></h1><p>How block attributes map to Tailwind-like classes on the frontend and in the editor.</p><h2 id="enable-per-block" tabindex="-1">Enable per block <a class="header-anchor" href="#enable-per-block" aria-label="Permalink to &quot;Enable per block&quot;">​</a></h2><p>In <code>block.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;supports&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;webentor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;layout&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;spacing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Here is the schema of <code>supports.webentor</code> in a scan-friendly format:</p><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>spacing</code></td><td><code>boolean</code></td><td>Enables Spacing controls (padding and margin).</td></tr><tr><td><code>layout</code></td><td><code>boolean | object</code></td><td><code>true</code> enables display mode controls. Use an object for granular control flags.</td></tr><tr><td><code>sizing</code></td><td><code>boolean | object</code></td><td><code>true</code> enables sizing controls. Use an object for granular width and height flags.</td></tr><tr><td><code>grid</code></td><td><code>boolean</code></td><td>Enables Grid controls.</td></tr><tr><td><code>gridItem</code></td><td><code>boolean</code></td><td>Enables Grid Item controls.</td></tr><tr><td><code>flexbox</code></td><td><code>boolean</code></td><td>Enables Flex controls.</td></tr><tr><td><code>flexItem</code></td><td><code>boolean</code></td><td>Enables Flex Item controls.</td></tr><tr><td><code>border</code></td><td><code>boolean</code></td><td>Enables Border controls.</td></tr><tr><td><code>borderRadius</code></td><td><code>boolean</code></td><td>Enables Border Radius controls.</td></tr><tr><td><code>blockLink</code></td><td><code>boolean</code></td><td>Enables Block Link controls.</td></tr><tr><td><code>presets</code></td><td><code>boolean</code></td><td>Enables the quick layout preset buttons.</td></tr></tbody></table><p>When <code>layout</code> is an object, use these properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>display</code></td><td><code>boolean</code></td><td>Shows display controls (e.g., <code>none</code>, <code>block</code>, <code>flex</code>, <code>grid</code>).</td></tr></tbody></table><p>When <code>sizing</code> is an object, use these properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>width</code></td><td><code>boolean</code></td><td>Shows width controls.</td></tr><tr><td><code>minWidth</code></td><td><code>boolean</code></td><td>Shows <code>min-width</code> controls.</td></tr><tr><td><code>maxWidth</code></td><td><code>boolean</code></td><td>Shows <code>max-width</code> controls.</td></tr><tr><td><code>height</code></td><td><code>boolean</code></td><td>Shows height controls.</td></tr><tr><td><code>minHeight</code></td><td><code>boolean</code></td><td>Shows <code>min-height</code> controls.</td></tr><tr><td><code>maxHeight</code></td><td><code>boolean</code></td><td>Shows <code>max-height</code> controls.</td></tr></tbody></table><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><p>Editor tabs are driven by <code>webentor.core.twBreakpoints</code> (default: <code>basic, sm, md, lg, xl, 2xl</code>). Classes are emitted with prefixes (<code>sm:pt-4</code>, <code>lg:grid-cols-3</code>).</p><h2 id="theme-tokens" tabindex="-1">Theme tokens <a class="header-anchor" href="#theme-tokens" aria-label="Permalink to &quot;Theme tokens&quot;">​</a></h2><p>Tokens come from <code>webentor.core.twTheme</code> (colors, spacing, radii, sizes). Ensure your <code>webentor-config.ts</code> safelists generated classes.</p><h2 id="quick-layout-presets" tabindex="-1">Quick layout presets <a class="header-anchor" href="#quick-layout-presets" aria-label="Permalink to &quot;Quick layout presets&quot;">​</a></h2><p>Core ships no preset catalog by default. Themes should register project-specific presets in editor JS with <code>webentor.core.responsiveSettings.layoutPresets</code>. The filter receives the current preset array, the active <code>blockName</code>, and the resolved theme tokens, so you can return presets per block or derive them from your theme config.</p><p>If you opt into <code>supports.webentor.presets</code>, the block gets the preset buttons even when it does not expose the rest of the layout controls. Any <code>customClasses</code> returned by a preset must exist in frontend CSS.</p><h2 id="rendering" tabindex="-1">Rendering <a class="header-anchor" href="#rendering" aria-label="Permalink to &quot;Rendering&quot;">​</a></h2><p>On render, Core computes:</p><ul><li><code>block_classes</code> – outer/wrapper classes (layout, spacing, display)</li><li><code>bg_classes</code> – background-related classes</li></ul><p>These are passed to Blade views and can be filtered via:</p><ul><li><code>webentor/block_classes(string $classes, WP_Block $block)</code></li><li><code>webentor/block_bg_classes(string $classes, WP_Block $block)</code></li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Provide only the property groups you need per block to keep UI focused.</li><li>Large class surfaces: rely on safelist generation in <code>webentor-config.ts</code>.</li><li>Combine with recipes like <a href="./../recipes/hero-banner.html">hero banner</a>.</li></ul>`,25)])])}const k=t(a,[["render",n]]);export{b as __pageData,k as default};
